// Calculating values for different bases raised to the powers 1/3 and 7/12
// And comparing them to e-related constants

const e = Math.E;
const oneOverE = 1/e;
const geosumOneOverE = 1/(e-1);
const geosumOneOverEPlusOne = 1/e;  // geosum(1/(e+1))

// Function to calculate values and compare with e-related constants
function analyzeValue(base, exponent) {
  const value = Math.pow(1/base, exponent);

  // Find n that makes value = geosum(1/n) = 1/(n-1)
  const n = 1 + 1/value;

  // Calculate differences and percentages
  const diffFromE = Math.abs(n - e);
  const relDiffFromE = (diffFromE / e * 100).toFixed(4);

  const diffFromOneOverE = Math.abs(value - oneOverE);
  const relDiffFromOneOverE = (diffFromOneOverE / oneOverE * 100).toFixed(4);

  const diffFromGeosum = Math.abs(value - geosumOneOverE);
  const relDiffFromGeosum = (diffFromGeosum / geosumOneOverE * 100).toFixed(4);

  return {
    base: base,
    exponent: exponent,
    value: value.toFixed(6),
    n: n.toFixed(6),
    diffFromE: diffFromE.toFixed(6),
    relDiffFromE: relDiffFromE + "%",
    diffFromOneOverE: diffFromOneOverE.toFixed(6),
