// Let's verify that b(n) = 1 + 2(1 + 2(1 + 2(...))) with n-1 nested expressions
// matches our recurrence relation b(1) = 2, b(n+1) = 2*b(n) - 1

// First, let's define a function to calculate b(n) using the recurrence relation
function calculateBRecurrence(n) {
  let b = 2; // b(1) = 2
  for(let i = 1; i < n; i++) {
    b = 2*b - 1; // b(n+1) = 2*b(n) - 1
  }
  return b;
}

// Now, let's define a function to calculate b(n) using the nested expression
// b(n) = 1 + 2(1 + 2(1 + 2(...))) with n-1 nested expressions
function calculateBNested(n) {
  // Base case: b(1) = 2
  if (n === 1) return 2;

  // For n > 1, we need to compute the nested expression
  let result = 1; // Start with the outermost 1
  for(let i = 0; i < n-1; i++) {
    result = 1 + 2 * result;
  }
  return result;
}

// Let's try an alternative formulation
// Using a recursive approach for the nested expression
function calculateBNestedRecursive(n) {
  if (n === 1) return 2;
  return 1 + 2 * calculateBNestedRecursive(n-1);
}

// Compare the results for the first 10 values of n
console.log("Comparing different methods to calculate b(n):");
console.log("| n | Recurrence | Nested | Recursive | Check |");
console.log("|---|------------|--------|-----------|-------|");

for(let n = 1; n <= 10; n++) {
  const bRecurrence = calculateBRecurrence(n);
  const bNested = calculateBNested(n);
  const bNestedRecursive = calculateBNestedRecursive(n);
  const check = bRecurrence === bNested && bRecurrence === bNestedRecursive ? "✓" : "✗";

  console.log(`| ${n} | ${bRecurrence} | ${bNested} | ${bNestedRecursive} | ${check} |`);
}

